public function store(Request $request)
{
    $dados = $request->validate([
        'nome'  => 'required|string|max:255',
        'email' => 'required|email|unique:users,email',
        'preco' => 'required|numeric|min:0',
        'foto'  => 'nullable|image|max:2048',  // opcional, imagem, max 2MB
    ]);

    // Se inválido: redireciona de volta com erros
    // Se válido: $dados contém apenas os campos validados
    Produto::create($dados);

    return redirect()->route('produtos.index')->with('sucesso', 'Produto criado!');
}

